Here are the public test cases for feature1_project_name_normalization:
{
  "description": "Directory names are converted into package-safe project names before being used in generated package metadata.",
  "cases": [
    {
      "input": {
        "scenario": "project_name_from_directory",
        "directory_name": "foo.dart"
      },
      "expected_output": "name=foo\n"
    },
    {
      "input": {
        "scenario": "project_name_from_directory",
