Here are the public test cases for feature2_template_placeholder_rendering:
{
  "description": "Text templates replace placeholders whose names are made only of letters, leave unknown placeholders unchanged, do not recursively expand replacement values, and report invalid placeholder keys neutrally.",
  "cases": [
    {
      "input": {
        "scenario": "template_placeholder_rendering",
        "text": "foo __bar__ baz",
        "variables": {
          "bar": "baz"
        }
      },
      "expected_output": "text=foo baz baz\n"
    },
    {
      "input": {
        "scenario": "template_placeholder_rendering",
        "text": "foo __bar__ baz",
        "variables": {
          "aaa": "bbb"
        }
      },
      "expected_output": "text=foo __bar__ baz\n"
    },
    {
      "input": {
        "scenario": "template_placeholder_rendering",
        "text": "foo __bar__ baz",
        "variables": {
          "bar": "__baz__",
          "baz": "foo"
        }
      },
      "expected_output": "text=foo __baz__ baz\n"
    },
    {
      "input": {
        "scenario": "template_placeholder_rendering",
        "text": "str",
        "variables": {
          "with space": "noop"
        }
      },
      "expected_output": "error=invalid_placeholder_key\nkey=with space\n"
    }
  ]
}

Here are the public test cases for feature3_plain_text_wrapping:
{
  "description": "Plain text is split at spaces when it exceeds the configured column width, preserving short text as a single line.",
  "cases": [
    {
      "input": {
        "scenario": "plain_text_wrapping",
        "text": "foo barbar baz"
      },
      "expected_output": "line_count=1\nline_0=foo barbar baz\n"
    },
    {
      "input": {
        "scenario": "plain_text_wrapping",
        "text": "foo barbar baz",
        "column": 10
      },
      "expected_output": "line_count=2\nline_0=foo barbar\nline_1=baz\n"
    }
  ]
}

