Here are the public test cases for feature6_project_generation_summary:
{
  "description": "Generating a selected project template writes the expected number of relative files, identifies the intended entrypoint, includes common metadata files, and substitutes the project name into package metadata.",
  "cases": [
    {
      "input": {
        "scenario": "project_generation_summary",
        "template_selector": "console-full",
        "project_name": "foo",
        "author": "Ada Lovelace"
      },
      "expected_output": "template=console-full\nproject_name=foo\nfile_count=9\nentrypoint=bin/main.dart\nhas_gitignore=present\nhas_pubspec=present\npubspec_name=foo\npubspec_version=0.0.1\npubspec_sdk='>=1.20.1 <2.0.0'\nfirst_file=.gitignore\nlast_file=test/foo_test.dart\n"
    },
    {
      "input": {
        "scenario": "project_generation_summary",
        "template_selector": "web-angular",
        "project_name": "foo",
        "author": "Ada Lovelace"
      },
      "expected_output": "template=web-angular\nproject_name=foo\nfile_count=15\nentrypoint=web/index.html\nhas_gitignore=present\nhas_pubspec=present\npubspec_name=foo\npubspec_version=0.0.1\npubspec_sdk='>=1.20.1 <2.0.0'\nfirst_file=.gitignore\nlast_file=web/styles.css\n"
    },
    {
      "input": {
        "scenario": "project_generation_summary",
        "template_selector": "bad-template",
        "project_name": "foo",
        "author": "Ada Lovelace"
      },
      "expected_output": "error=unknown_template\ntemplate_selector=bad-template\n"
    }
  ]
}

